module.render:
    const color = args.color || 'var(--accent-color)';
    const sizes = { sm: '0.9em', md: '1em', lg: '1.15em' };
    const size = sizes[String(args.size || 'md').toLowerCase()] || '1em';
    const aligns = { left: 'left', center: 'center', right: 'right' };
    const align = aligns[String(args.align || 'left').toLowerCase()] || 'left';
    const boxed = String(args.boxed) === 'true';
    const cls = 'mdp-mod-definition' + (boxed ? ' mdp-def-boxed' : '');
    const termStr = sections[0] ? sections[0].trim() : '';
    const defStr = sections[1] ? sections[1].trim() : '';
    return `

<div class="${cls}" style="--def-color: ${color}; font-size: ${size}; text-align: ${align};"><div class="definition-term" style="color: ${color};">

${termStr}

</div><div class="definition-body" style="border-left-color: ${color};">

${defStr}

</div></div>

`;
